    CUR: { fullName: 'Windows Cursor File', purpose: 'CUR is the Windows static mouse-cursor format, closely related to ICO but with a defined click hotspot.', stores: 'It can package one or more bitmap or PNG cursor images plus horizontal and vertical hotspot coordinates.', compatibility: 'Windows supports CUR directly; general image editors may show the graphic without preserving hotspot behavior.', uses: ['Windows mouse pointers', 'Application cursor resources', 'Desktop themes', 'Custom interface states'], apps: ['Windows Mouse Properties', 'RealWorld Cursor Editor', 'GIMP'], strength: 'Combines cursor artwork with precise hotspot coordinates', limitation: 'Primarily useful on Windows and not interchangeable with ordinary icons', conversion: 'Convert CUR artwork to PNG for editing, then use a cursor editor to restore size variants and hotspot coordinates when exporting back.' },
    APNG: { fullName: 'Animated Portable Network Graphics', purpose: 'APNG extends PNG to support full-color, alpha-transparent frame animation.', stores: 'It contains a standard PNG image plus animation-control and frame-data chunks with timing, sequence, and disposal information.', compatibility: 'Modern browsers support APNG; some older PNG tools display only the default first frame.', uses: ['Transparent web animations', 'Animated interface graphics', 'High-color stickers', 'Lossless short loops'], apps: ['A modern web browser', 'GIMP with support', 'APNG Assembler'], strength: 'Full-color lossless animation with alpha transparency', limitation: 'Files can be much larger than lossy video or animated WebP/AVIF', conversion: 'Convert APNG to animated WebP or video for smaller delivery, or extract frames to PNG. Verify looping, disposal, timing, and transparency.' },
