const makeDesignProfile = (seed: ImageSeed): DocumentEditorialProfile => ({
  fullName: seed.fullName, purpose: seed.purpose, stores: seed.stores, compatibility: seed.compatibility, uses: seed.uses,
  advantages: [seed.strength, 'Preserves editable creative-project information', 'Supports export to delivery formats', 'Keeps related design elements in a structured project'],
  disadvantages: [seed.limitation, 'Missing fonts or linked assets can change output', 'Application-version differences can affect editing', 'Complex projects can be large and resource-intensive'],
  openWith: seed.apps,
  openInstructions: `Open the project with ${seed.apps.slice(0, 2).join(' or ')}. Work from a copy and check fonts, linked assets, layers, color settings, effects, and application version.`,
  conversionAdvice: seed.conversion,
});

