type ArchiveSeed = {
  fullName: string; purpose: string; stores: string; compatibility: string;
  uses: string[]; apps: string[]; strength: string; limitation: string; conversion: string;
};
const makeArchiveProfile = (seed: ArchiveSeed): DocumentEditorialProfile => ({
  fullName: seed.fullName, purpose: seed.purpose, stores: seed.stores, compatibility: seed.compatibility, uses: seed.uses,
  advantages: [seed.strength, 'Keeps packaged content together for transfer or storage', 'Can be inspected with compatible archive tools', 'Supports reproducible extraction when the archive is intact'],
  disadvantages: [seed.limitation, 'Damaged archives can prevent access to contained files', 'Untrusted archives can hide malicious content', 'Passwords cannot be recovered reliably when lost'],
  openWith: seed.apps,
  openInstructions: `Open the archive with ${seed.apps.slice(0, 2).join(' or ')}. Inspect its contents before extraction, reject suspicious paths or executables, and extract into a new folder rather than over important files.`,
  conversionAdvice: seed.conversion,
});
