    '7Z': { fullName: '7-Zip Compressed Archive', purpose: '7Z is an open archive container used by 7-Zip for high compression, solid archives, and strong AES-256 encryption.', stores: 'It can package file trees with selectable codecs, filters, checksums, solid blocks, headers, and optional encrypted filenames.', compatibility: '7-Zip and many desktop archive applications support 7Z; operating systems may not open it without additional software.', uses: ['High-compression software packages', 'Encrypted file bundles', 'Large archival collections', 'Solid-compressed backups'], apps: ['7-Zip', 'PeaZip', 'Keka'], strength: 'High compression efficiency and strong encryption options', limitation: 'Solid compression can make individual recovery slower and native OS support is limited', conversion: 'Extract 7Z and recreate ZIP for broader access or TAR.XZ for Unix workflows. Validate passwords, file hashes, names, permissions, and symbolic links.' },
    TAR: { fullName: 'Tape Archive', purpose: 'TAR packages Unix files, directories, links, ownership, permissions, and timestamps without necessarily compressing them.', stores: 'It writes sequential file headers and content blocks and is commonly combined with gzip, bzip2, or xz compression.', compatibility: 'Unix tools support TAR natively; modern Windows archive tools also extract common variants.', uses: ['Unix software source packages', 'Filesystem backups', 'Container build contexts', 'Preserving file permissions and links'], apps: ['tar command', '7-Zip', 'PeaZip'], strength: 'Preserves Unix filesystem metadata and directory structure', limitation: 'Plain TAR does not reduce size and unsafe paths or links require careful extraction', conversion: 'Compress TAR as TAR.GZ or TAR.XZ rather than converting when Unix metadata matters. Inspect absolute paths, traversal entries, owners, permissions, and links.' },
    GZ: { fullName: 'GNU Zip Compressed Stream', purpose: 'GZ uses gzip compression on one data stream and is often paired with TAR for multi-file archives.', stores: 'It contains DEFLATE-compressed data plus a header, optional original filename and timestamp, and a CRC checksum.', compatibility: 'Unix, browser, and archive tools support gzip broadly; one .gz file normally represents one compressed file.', uses: ['Compressing logs', 'Web content encoding', 'Creating TAR.GZ packages', 'Distributing Unix data files'], apps: ['gzip or gunzip', '7-Zip', 'PeaZip'], strength: 'Fast, established compression with broad support', limitation: 'It does not natively package multiple files or preserve directory structures', conversion: 'Decompress GZ to recover its original stream. Use TAR.GZ for folders, ZIP for a broadly accessible multi-file archive, and verify the CRC.' },
    TGZ: { fullName: 'Gzipped TAR Archive', purpose: 'TGZ is the shortened extension for a TAR archive compressed with gzip.', stores: 'The inner TAR preserves paths and Unix metadata while the outer gzip stream reduces the package size.', compatibility: 'Unix tar, 7-Zip, and modern archive tools support TGZ; some interfaces show two extraction stages.', uses: ['Linux software distribution', 'Source-code packages', 'Server backups', 'Transferring Unix directory trees'], apps: ['tar command', '7-Zip', 'PeaZip'], strength: 'Combines Unix metadata preservation with fast gzip compression', limitation: 'Random access is limited because the compressed TAR is sequential', conversion: 'Extract TGZ safely or recompress as TAR.XZ for size and ZIP for broader desktop convenience. Preserve permissions, links, hidden files, and executable bits.' },
    BZ2: { fullName: 'bzip2 Compressed Stream', purpose: 'BZ2 uses bzip2 block-sorting compression on a single file or TAR stream.', stores: 'It contains compressed blocks with integrity checks but no native multi-file directory index.', compatibility: 'Unix tools and mature archive applications support BZ2; decompression is slower than gzip in many workflows.', uses: ['Compressing Unix data files', 'Creating TAR.BZ2 source packages', 'Archiving text-heavy data', 'Distributing legacy Linux packages'], apps: ['bzip2 or bunzip2', '7-Zip', 'PeaZip'], strength: 'Often compresses text better than gzip', limitation: 'Slower processing and no built-in multi-file packaging', conversion: 'Decompress BZ2 to recover the original file, or use TAR.BZ2 for packaged directories. Recompress only from the uncompressed source and verify integrity.' },
    XZ: { fullName: 'XZ Compressed Stream', purpose: 'XZ uses LZMA2 compression for compact single-stream files and Unix TAR.XZ packages.', stores: 'It contains compressed blocks, filters, indexes, and strong checksums, but directory structure normally comes from an inner TAR.', compatibility: 'Modern Unix systems and archive tools support XZ; older software may lack it.', uses: ['Linux package compression', 'TAR.XZ source archives', 'Compressing large text or binary files', 'Long-term distribution packages'], apps: ['xz or unxz', '7-Zip', 'PeaZip'], strength: 'High compression ratios with integrity checks and indexed streams', limitation: 'Compression can consume substantial CPU and memory', conversion: 'Decompress XZ or its TAR payload, then choose gzip for speed or ZIP for desktop compatibility. Verify checksums and preserve TAR metadata.' },
    CAB: { fullName: 'Microsoft Cabinet Archive', purpose: 'CAB is Microsoft’s archive format for packaging Windows installation files, drivers, and system components.', stores: 'It can contain multiple files, folders, checksums, compression blocks, and split-cabinet relationships used by installers.', compatibility: 'Windows setup tools support CAB natively; 7-Zip and similar tools inspect many cabinets but do not replace installation logic.', uses: ['Windows driver packages', 'Operating-system components', 'Software installers', 'Microsoft update payloads'], apps: ['Windows expand command', '7-Zip', 'DISM for appropriate packages'], strength: 'Integrated with Windows deployment and installation systems', limitation: 'Extracting files does not safely reproduce installer actions or trust checks', conversion: 'Extract CAB only for authorized inspection. Do not convert a driver or update cabinet and expect it to remain installable; preserve signatures, manifests, and package structure.' },
