const formatIcon = (category: FormatCategory) => {
  if (category === 'Spreadsheet' || category === 'Database' || category === 'Data') return spreadsheetIcon;
  if (category === 'Presentation') return presentationIcon;
  if (category === 'Image' || category === 'Design') return designIcon;
  if (category === 'Audio' || category === 'Video') return presentationIcon;
  if (category === 'Security' || category === 'Executable') return securityIcon;
  if (category === '3D' || category === 'Font') return designIcon;
  return wordIcon;
};

const conversionLinks = (category: FormatCategory) => {
  if (category === 'Spreadsheet') return [{ label: 'Convert Excel to PDF', href: '/tools/excel-to-pdf' }, { label: 'Convert XLSX to CSV', href: '/tools/xlsx-to-csv' }];
  if (category === 'Presentation') return [{ label: 'Convert PPTX to PDF', href: '/tools/pptx-to-pdf' }];
  return [{ label: 'Browse FileBrother tools', href: '/#tools' }];
};

const createFormatPost = (format: FormatDefinition): BlogPost => {
  const fallbackContent = categoryContent[format.category];
  const editorial = documentEditorialProfiles[format.name]
    ?? ebookEditorialProfiles[format.name]
    ?? dataEditorialProfiles[format.name]
    ?? configEditorialProfiles[format.name]
    ?? subtitleEditorialProfiles[format.name]
    ?? spreadsheetEditorialProfiles[format.name]
    ?? (format.category === 'Database' ? databaseEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Presentation' ? presentationEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'CAD' ? cadEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Image' ? imageEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Design' ? designEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Audio' ? audioEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Video' ? videoEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Archive' ? archiveEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Code' ? codeEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Executable' ? executableEditorialProfiles[format.name] : undefined)
    ?? (format.category === '3D' ? threeDEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Font' ? fontEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Security' ? securityEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Misc' ? miscEditorialProfiles[format.name] : undefined)
    ?? (format.category === 'Map/GIS' ? mapGisEditorialProfiles[format.name] : undefined);
  const uses = editorial?.uses ?? fallbackContent.uses;
  const advantages = editorial?.advantages ?? fallbackContent.advantages;
  const disadvantages = editorial?.disadvantages ?? fallbackContent.disadvantages;
  const openWith = editorial?.openWith ?? fallbackContent.openWith;
  const displayCategory = format.category.toLowerCase();
  const mimeType = format.mimeType ?? 'application/octet-stream';
  const developerText = format.developedBy
    ? `The format is associated with ${format.developedBy}.`
    : 'The format is supported by various developers and applications.';
  const usesText = uses.map((use) => use.toLowerCase()).join(', ');
  const editorialOverview = editorial ? [
    `${format.name} is the ${editorial.fullName}, a ${displayCategory} format identified by the ${format.extension} extension and the MIME type ${mimeType}. ${editorial.purpose} ${editorial.stores} ${developerText}`,
    `${editorial.compatibility} People use ${format.name} files for ${usesText}. Important strengths include ${advantages.slice(0, 2).map((item) => item.toLowerCase()).join(' and ')}. These qualities explain why the format remains useful in the workflows and software that support it.`,
    `Before opening or converting ${format.name}, remember that ${disadvantages.slice(0, 2).map((item) => item.toLowerCase()).join(' and ')}. ${editorial.openInstructions} ${editorial.conversionAdvice} Keep the original file until the converted version has been checked for missing text, layout changes, metadata, or unsupported features.`,
  ] : undefined;

  return {
    seoReady: Boolean(editorial),
    slug: format.slug ?? `what-is-a-${format.name.toLowerCase()}-file`,
    shortTitle: `${format.name} File Guide`,
    title: `What Is a ${format.name} File? How to Open, Use & Convert ${format.name}`,
    description: `Learn what a ${format.name} file is, how to open ${format.extension} files on any device, common uses, advantages, disadvantages, safety tips, and how to convert them online.`,
    keywords: [`what is ${format.name}`, `open ${format.name}`, `${format.extension} file`, `${format.name} file guide`],
    h1: `${format.name} File — Complete Guide`,
    eyebrow: `${format.category} format guide`,
    intro: editorial
      ? `A ${format.name} (${editorial.fullName}) file uses the ${format.extension} extension. ${editorial.purpose} People commonly choose it for ${uses.slice(0, 2).map((use) => use.toLowerCase()).join(' and ')}. Knowing how the format stores information helps you open it with compatible software and convert it without losing important content.`
      : `A ${format.name} file is a ${displayCategory} format identified by the ${format.extension} extension. It stores information for compatible applications and is commonly used for ${uses.slice(0, 2).map((use) => use.toLowerCase()).join(' and ')}. Understanding the format helps you choose the right software, protect the original data, and convert the file without unnecessary quality or formatting loss.`,
    icon: formatIcon(format.category),
    fileDetails: [
      { property: 'Extension', value: format.extension },
      { property: 'Category', value: format.category },
      { property: 'MIME Type', value: mimeType },
      { property: 'Developed By', value: format.developedBy ?? 'Various developers' },
    ],
    whatIsIt: editorialOverview ?? [
      `${format.name} is a ${displayCategory} file format identified by the ${format.extension} extension and the MIME type ${mimeType}. ${developerText} An operating system uses the extension to identify the file, while compatible software reads the internal structure and presents its contents. The exact information stored inside depends on the format, the application that created it, and the options selected when the file was saved.`,
      `People commonly use ${format.name} files for ${usesText}. The format can be convenient because ${advantages.slice(0, 2).map((item) => item.toLowerCase()).join(' and ')}. However, users should also consider that ${disadvantages.slice(0, 2).map((item) => item.toLowerCase()).join(' and ')}. Support may vary between operating systems and application versions, so an unfamiliar file may not open correctly in the first program you try.`,
      `To work with a ${format.name} file, choose software that explicitly supports ${format.extension}. Opening the file in an unrelated application or simply renaming its extension does not convert its underlying data. If you need another format, use a trusted conversion tool, review the output carefully, and keep the original until the result is verified. Scan files received from unknown sources and avoid exposing private information when using online services.`,
    ],
    commonUses: uses,
    advantages,
    disadvantages,
    openWith,
    openInstructions: editorial?.openInstructions ?? `Open a ${format.name} file with an application that supports ${format.extension} files. If your device does not recognize it, install a compatible viewer or editor and avoid renaming the extension, because renaming does not convert the file.`,
    conversionIntro: editorial?.conversionAdvice ?? `You can convert a ${format.name} file when you need broader compatibility or a different workflow. Available output formats depend on the source file and the software used. Choose a trusted tool, review the converted result, and keep the original ${format.extension} file as a backup.`,
    conversions: conversionLinks(format.category),
    faqs: [
      { question: `What is a ${format.name} file used for?`, answer: `${format.name} files are used for ${uses.slice(0, 2).join(' and ').toLowerCase()}.` },
      { question: `How do I open a ${format.name} file?`, answer: editorial?.openInstructions ?? `Use an application that supports the ${format.extension} format. The available program depends on your operating system and the software that created the file.` },
      { question: `Can I convert a ${format.name} file?`, answer: editorial?.conversionAdvice ?? `Often yes, but available output formats depend on the source file and the conversion software. Keep the original file until you verify the converted result.` },
      { question: `Is a ${format.name} file safe?`, answer: `${format.name} files are generally safe when they come from a trusted source. Scan unexpected downloads or attachments and avoid running scripts, macros, or executable content you do not trust.` },
    ],
    relatedSlugs: [],
    publishedAt: '2026-06-22',
    updatedAt: '2026-06-22',
  };
};

const generatedBlogPosts = formatDefinitions.map(createFormatPost);
const orderedBlogPosts = [featuredBlogPosts[0], generatedBlogPosts[0], featuredBlogPosts[1], ...generatedBlogPosts.slice(1)];

export const blogPosts: BlogPost[] = orderedBlogPosts.map((post, _index, allPosts) => {
  if (post.relatedSlugs.length > 0) return post;
  const category = post.fileDetails.find((detail) => detail.property === 'Category')?.value;
  return {
    ...post,
    relatedSlugs: allPosts
      .filter((candidate) => candidate.slug !== post.slug && candidate.fileDetails.some((detail) => detail.property === 'Category' && detail.value === category))
      .slice(0, 2)
      .map((candidate) => candidate.slug),
  };
});

export const getBlogPost = (slug: string) => blogPosts.find((post) => post.slug === slug);

export const getBlogPostByFileSlug = (fileSlug: string) => {
  const normalizedFileSlug = fileSlug.toLowerCase();

  return blogPosts.find((post) => {
    const extension = post.fileDetails
      .find((detail) => detail.property === 'Extension')
      ?.value
      .replace(/^\./, '')
      .toLowerCase();

    return extension === normalizedFileSlug;
  });
};
